<script>
import { ref } from "vue";
export default {
  setup() {
    // Drop Menu for small devices 
    const dropMenu = (e) => {
      const element = e.target.previousElementSibling;
      if (element.classList.contains("show-menu")) {
        element.classList.remove("show-menu");
      } else {
        element.classList.add("show-menu");
      }
    };
    // function that make nav transparent 
    document.addEventListener("scroll", () => {
      if (window.pageYOffset >= 100) {
        document.querySelector(".nav").style.background = `rgba(0,0,0,.7)`;
      } else if (window.pageYOffset < 100) {
        document.querySelector(".nav").style.background = `#111`;
      }
      if(window.pageYOffset >= 940 ){
       const x =  document.querySelectorAll(".main-ul > li")
       
      }
    });
    return { dropMenu };
  },
};
</script>

