<template>
  <div class="project">
    <!-- project heading  -->
    <h1 class="project-heading">
      project
    </h1>
    <!-- project nav to selected which content to see  -->
    <nav class="project-nav">
      <ul class="project-ul">
        <li class="project-li selected" @click="changeCategory">all</li>
        <li class="project-li" @click="changeCategory">vue</li>
        <li class="project-li" @click="changeCategory">javascript</li>
        <li class="project-li" @click="changeCategory">node</li>
      </ul>
    </nav>
    <!-- project showcase display all project here  -->
    <div class="project-showcase">
      <section
        data-aos="zoom-in"
        :class="{ content: true }"
        v-for="data in showContent"
        :key="data.id"
      >
        <div class="img">
          <img
            class="project-img"
            loading="lazy"
            width="300px"
            height="100%"
            :src="data.image.replace('/img','img')"
            alt="Project-img"
          />
        </div>
        <p>{{ data.paragraph }}</p>
        <a target="_blank" :href="data.link">visit project</a>
      </section>
    </div>
  </div>
</template>

<script>
import { onMounted, ref } from "vue";
export default {
  setup() {
    // All projects
    const content = ref([
      {
        id: 1,
        image: require("../assets/images/1.webp"),
        paragraph: "vue.js, scss , node.js , express.js ",
        link: "https://getmovies-34c94.web.app/",
      },
      {
        id: 2,
        image: require("../assets/images/2.webp"),
        paragraph: "vue.js , scss",
        link: "/",
      },
      {
        id: 3,
        image: require("../assets/images/3.webp"),
        paragraph: "html , scss , javascript",
        link: "https://ajjlalahmed.github.io/Calculator/",
      },
      {
        id: 4,
        image: require("../assets/images/4.webp"),
        paragraph: "html , scss , javascript",
        link: "https://ajjlalahmed.github.io/Miami/",
      },
      {
        id: 5,
        image: require("../assets/images/5.webp"),
        paragraph: "html , scss , javascript",
        link: "https://ajjlalahmed.github.io/Doob/",
      },
      {
        id: 6,
        image: require("../assets/images/6.webp"),
        paragraph: "html , scss , javascript , node.js , express.js, mongodb",
        link: "https://host-cloud.herokuapp.com/",
      },
      {
        id: 7,
        image: require("../assets/images/7.webp"),
        paragraph: "html , scss , javascript",
        link: "https://ajjlalahmed.github.io/portfolio-website/",
      },
      {
        id: 8,
        image: require("../assets/images/8.webp"),
        paragraph: "html , javascript , scss",
        link: "https://ajjlalahmed.github.io/Music-App/",
      },
    ]);
    // Projects that showed every time
    const showContent = ref(content.value);
    //Function that create temporary content to display
    const createContent = (search) => {
      let newShowContent = ref([]);
      showContent.value = null;
      content.value.forEach((element) => {
        if (element.paragraph.includes(search)) {
          newShowContent.value.push({
            id: element.id,
            image: element.image,
            paragraph: element.paragraph,
            link: element.link,
          });
        }
      });
      showContent.value = newShowContent.value;
    };
    // Function that check what content to display next
    const changeCategory = (e) => {
      const currentValue = ref(e.target.innerHTML);
      document.querySelectorAll(".project-li").forEach((item) => {
        item.classList.remove("selected");
      });
      e.target.classList.add("selected");
      if (currentValue.value == "all") {
        showContent.value = content.value;
        return;
      } else if (currentValue.value == "vue") {
        createContent("vue");
      } else if (currentValue.value == "javascript") {
        createContent("javascript");
      } else if (currentValue.value == "node") {
        createContent("node.js");
      }
    };
    return { content, changeCategory, showContent, createContent };
  },
};
</script>

<style lang="scss">
// Variables
$primary-color: #05c2c9;
$secondary-color: #111;
$white: #fff;
$text: rgb(226, 226, 226);
.project {
  background: $secondary-color;
  padding: 40px 0px;
  min-height: 100vh;
  overflow: hidden;
  max-width: 1660px;
  margin: 0 auto;
  .project-heading {
    font-size: 3rem;
    text-transform: capitalize;
    text-align: center;
    color: $white;
    font-weight: 300;
    padding: 50px 0px;
  }
  .project-nav {
    background: $white;
    padding: 10px;
    margin: 0 auto;
    margin-bottom: 50px;
    width: 80%;
    .project-ul {
      display: flex;
      list-style: none;
      justify-content: center;
      .project-li {
        padding: 5px 20px;
        text-transform: capitalize;
        font-size: 1rem;
        font-weight: 700;
        cursor: pointer;
        border-radius: 3px;
      }
    }
  }
  .project-showcase {
    display: flex;
    justify-content: center;
    gap: 40px;
    width: 90%;
    flex-wrap: wrap;
    margin: 0 auto;
    .content {
      max-width: 350px;
      background: $white;
      border-radius: 2px;
      padding-bottom: 10px;
      transition: 0.3s ease-in-out;
      &:hover {
        transform: scale(1.1);
      }
      .img {
        min-height: 200px;
        img {
          width: 300px;
          height: 200px;
          object-fit: cover;
        }
      }
      p {
        font-size: 0.9rem;
        font-weight: 700;
        color: $secondary-color;
        padding: 10px 5px;
        width: 250px;
        min-height: 40px;
        text-transform: uppercase;
      }
      a {
        text-decoration: none;
        text-transform: capitalize;
        font-size: 1rem;
        background: $primary-color;
        padding: 5px 10px;
        color: $white;
        margin: 0px 5px;
        border-radius: 2px;
        transition: 0.3s ease-in-out;
        font-weight: 700;
        &:hover {
          background: $secondary-color;
        }
      }
    }
  }
  .selected {
    background: $secondary-color;
    color: $white;
  }
}
@media only screen and(max-width:400px) {
  .project {
    .project-nav {
      width: 100%;
      .project-ul {
        .project-li {
          padding: 10px;
        }
      }
    }
  }
}
</style>
